const err = $input.item.json;
const errorMsg = (err.execution?.error?.message || err.error?.message || err.message || JSON.stringify(err)).toLowerCase();
const statusCode = err.execution?.error?.statusCode || err.error?.statusCode || err.statusCode || 0;
const rawBody = JSON.stringify(err.execution?.error || err.error || err);

const isCredits =
  statusCode === 402 ||
  statusCode === 429 ||
  errorMsg.includes('402') ||
  errorMsg.includes('credits') ||
  errorMsg.includes('insufficient') ||
  errorMsg.includes('out of credits') ||
  errorMsg.includes('quota') ||
  rawBody.toLowerCase().includes('credits') ||
  rawBody.toLowerCase().includes('insufficient');

let brandId = null;
let productId = null;
try {
  const runData = err.execution?.data?.resultData?.runData || {};
  const validarNode = runData['Validar Input']?.[0]?.data?.main?.[0]?.[0]?.json;
  if (validarNode) {
    brandId = validarNode.brand_id || null;
    productId = validarNode.product_id || null;
  }
} catch(e) {}

const errorType = isCredits ? 'credits_exhausted' : 'service_down';
const severity = isCredits ? 'error' : 'warning';
const title = isCredits ? 'Creditos OpenRouter agotados' : 'Error en generacion de imagen';
const errorDetail = err.execution?.error?.message || err.error?.message || err.message || 'desconocido';
const message = isCredits
  ? 'Los creditos de OpenRouter se han agotado. El servicio de generacion esta caido. Error: ' + errorDetail
  : 'Fallo en el workflow de generacion. Tipo: ' + errorType + ' | Error: ' + errorDetail;

return { json: {
  type: errorType,
  title,
  message,
  severity,
  brand_id: brandId,
  brand_name: null,
  metadata: JSON.stringify({
    product_id: productId,
    status_code: statusCode,
    execution_id: err.execution?.id || null,
    raw_error: rawBody.substring(0, 500),
    timestamp: new Date().toISOString()
  })
}};
